import{_ as n,o as r,c as t,ag as a}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Wiederkehrende Ausgaben","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/recurring-expenses.md","filePath":"de/features/recurring-expenses.md"}'),i={name:"de/features/recurring-expenses.md"};function s(l,e,o,d,h,u){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="wiederkehrende-ausgaben" tabindex="-1">Wiederkehrende Ausgaben <a class="header-anchor" href="#wiederkehrende-ausgaben" aria-label="Permalink to &quot;Wiederkehrende Ausgaben&quot;">​</a></h1><p>Automatisieren Sie die Erfassung regelmäßiger Geschäftskosten wie Miete, Abonnements und Nebenkosten.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Wiederkehrende Ausgaben funktionieren wie wiederkehrende Rechnungen, aber für Kosten. Richten Sie eine Vorlage ein und lassen Sie MyCompanyDesk automatisch Ausgabendatensätze erstellen.</p><p>Häufige Anwendungsfälle:</p><ul><li>Büromiete</li><li>Software-Abonnements</li><li>Versicherungsprämien</li><li>Nebenkostenabrechnungen</li><li>Leasingzahlungen</li></ul><h2 id="wiederkehrende-ausgabe-erstellen" tabindex="-1">Wiederkehrende Ausgabe erstellen <a class="header-anchor" href="#wiederkehrende-ausgabe-erstellen" aria-label="Permalink to &quot;Wiederkehrende Ausgabe erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Wiederkehrende Ausgaben &gt; Neu</strong></li><li>Füllen Sie die Vorlage aus: <ul><li><strong>Beschreibung</strong> — Wofür die Ausgabe ist</li><li><strong>Betrag</strong> — Die wiederkehrenden Kosten</li><li><strong>Kategorie</strong> — Ausgabenkategorie</li><li><strong>USt.-Satz</strong> — Anwendbare USt.</li><li><strong>Häufigkeit</strong> — Wöchentlich, monatlich, vierteljährlich oder jährlich</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h2 id="haufigkeitsoptionen" tabindex="-1">Häufigkeitsoptionen <a class="header-anchor" href="#haufigkeitsoptionen" aria-label="Permalink to &quot;Häufigkeitsoptionen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Häufigkeit</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Wöchentlich</strong></td><td>Alle 7 Tage</td></tr><tr><td><strong>Monatlich</strong></td><td>Am gleichen Tag jeden Monat</td></tr><tr><td><strong>Vierteljährlich</strong></td><td>Alle 3 Monate</td></tr><tr><td><strong>Jährlich</strong></td><td>Einmal pro Jahr</td></tr></tbody></table><h2 id="wiederkehrende-ausgaben-verwalten" tabindex="-1">Wiederkehrende Ausgaben verwalten <a class="header-anchor" href="#wiederkehrende-ausgaben-verwalten" aria-label="Permalink to &quot;Wiederkehrende Ausgaben verwalten&quot;">​</a></h2><h3 id="pausieren-fortsetzen" tabindex="-1">Pausieren / Fortsetzen <a class="header-anchor" href="#pausieren-fortsetzen" aria-label="Permalink to &quot;Pausieren / Fortsetzen&quot;">​</a></h3><p>Schalten Sie die automatische Generierung ein oder aus. Pausieren stoppt die Erstellung neuer Ausgaben; Fortsetzen setzt ab dem nächsten geplanten Datum fort.</p><h3 id="bearbeiten" tabindex="-1">Bearbeiten <a class="header-anchor" href="#bearbeiten" aria-label="Permalink to &quot;Bearbeiten&quot;">​</a></h3><p>Änderungen an der Vorlage betreffen nur zukünftige Ausgaben. Bestehende Ausgaben werden nicht geändert.</p><h3 id="loschen" tabindex="-1">Löschen <a class="header-anchor" href="#loschen" aria-label="Permalink to &quot;Löschen&quot;">​</a></h3><p>Entfernen Sie die Vorlage. Bereits generierte Ausgaben bleiben in Ihren Unterlagen.</p><h2 id="generierte-ausgaben" tabindex="-1">Generierte Ausgaben <a class="header-anchor" href="#generierte-ausgaben" aria-label="Permalink to &quot;Generierte Ausgaben&quot;">​</a></h2><p>Jede generierte Ausgabe:</p><ul><li>Entspricht dem Betrag, der Kategorie und den USt.-Einstellungen der Vorlage</li><li>Wird auf das geplante Vorkommensdatum datiert</li><li>Kann nach der Erstellung unabhängig bearbeitet werden</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Überprüfen Sie Ihre wiederkehrenden Ausgaben regelmäßig, um gekündigte Abonnements zu erkennen</li><li>Verknüpfen Sie wiederkehrende Ausgaben mit Projekten für eine genaue Projektkostenkalkulation</li><li>Verwenden Sie Kategorien konsequent für aussagekräftige Berichte</li></ul>',22)])])}const c=n(i,[["render",s]]);export{b as __pageData,c as default};
